using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    // create a new document
    Ptr docs = app->documents();
    if (!docs)
        return false;

    Ptr doc = docs->add(FusionDesignDocumentType);
    if (!doc)
        return false;

    // get the design
    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // get the root component of the active design.
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // create a new sketch on the xy plane.
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;

    Ptr xyPlane = rootComp->xYConstructionPlane();
    if (!xyPlane)
        return false;

    Ptr sketch = sketches->add(xyPlane);
    if (!sketch)
        return false;

    // create a sketch circle
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;

    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;

    Ptr sketchCircle = sketchCircles->addByCenterRadius(Point3D::create(0, 0, 0), 3.0);
    if (!sketchCircle)
        return false;

    Ptr profiles = sketch->profiles();
    if (!profiles)
        return false;

    // get the profile defined by the circle.
    Ptr profile = profiles->item(0);
    if (!profile)
        return false;

    // Create an extrusion input
    Ptr features = rootComp->features();
    if (!features)
        return false;

    Ptr extrudes = features->extrudeFeatures();
    if (!extrudes)
        return false;

    Ptr extrudeInput = extrudes->createInput(profile, NewBodyFeatureOperation);
    if (!extrudeInput)
        return false;

    // Define that the extent is a distance extent of 7 cm.
    bool bRet = extrudeInput->setDistanceExtent(false, ValueInput::createByReal(7));
    if (!bRet)
        return false;

    // Create the extrusion.
    Ptr extrude = extrudes->add(extrudeInput);
    if (!extrude)
        return false;

    // define all of the thread information.
    Ptr threadFeatures = features->threadFeatures();
    if (!threadFeatures)
        return false;

    // query the thread table to get the thread information
    Ptr threadDataQuery = threadFeatures->threadDataQuery();
    if (!threadDataQuery)
        return false;
    std::vector threadTypes = threadDataQuery->allThreadTypes();
    if (threadTypes.size() == 0)
        return false;
    std::string threadType = threadTypes[0];

    std::vector allsizes = threadDataQuery->allSizes(threadType);
    if (allsizes.size() == 0)
        return false;
    std::string threadSize = allsizes[0];

    std::vector allDesignations = threadDataQuery->allDesignations(threadType, threadSize);
    if (allDesignations.size() == 0)
        return false;
    std::string threadDesignation = allDesignations[0];

    std::vector allClasses = threadDataQuery->allClasses(false, threadType, threadDesignation);
    if (allClasses.size() == 0)
        return false;
    std::string threadClass = allClasses[0];

    // create the threadInfo according to the query result
    Ptr threadInfo = threadFeatures->createThreadInfo(false, threadType, threadDesignation, threadClass);
    if (!threadInfo)
        return false;

    // get the face the thread will be applied to
    Ptr sideFaces = extrude->sideFaces();
    if (!sideFaces)
        return false;

    Ptr sideface = sideFaces->item(0);
    if (!sideface)
        return false;
    Ptr faces = ObjectCollection::create();
    if (!faces)
        return false;
    faces->add(sideface);

    // define the thread input with the lenght 3.5 cm
    Ptr threadInput = threadFeatures->createInput(faces, threadInfo);
    if (!threadInput)
        return false;

    threadInput->isFullLength(false);
    threadInput->threadLength(ValueInput::createByReal(3.5));

    // create the final thread
    Ptr thread = threadFeatures->add(threadInput);
    if (!thread)
        return false;


    return true;
}
